import { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import API from "../../services/api";
import "./css/Login.css";

function Register() {
  const navigate = useNavigate();
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const handleRegister = async (e) => {
    e.preventDefault();
    try {
      const res = await API.post("/auth/register", {
        name,
        email,
        password,
        role: "User"
      });

      alert("Registration Successful. Please Sign In.");
      navigate("/");
    } catch (err) {
      alert("Registration Failed.");
    }
  };

  return (
    <div className="auth-page-bg" style={{ 
      background: 'linear-gradient(135deg, #bfdbfe 0%, #fbcfe8 100%)' 
    }}>
      <div className="auth-card-modern" style={{ textAlign: "center" }}>

        <div style={{
          width: '64px',
          height: '64px',
          background: '#ffffff',
          borderRadius: '16px',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          margin: '0 auto 1rem',
          boxShadow: '0 4px 6px rgba(0,0,0,0.05)',
          fontSize: '2rem',
          color: '#fb7185'
        }}>
          <svg style={{width:'32px', height:'32px'}} fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M18 9v3m0 0v3m0-3h3m-3 0h-3m-2-5a4 4 0 11-8 0 4 4 0 018 0zM3 20a6 6 0 0112 0v1H3v-1z" /></svg>
        </div>

        <div className="auth-header-modern">
          <h1 style={{color: '#0f172a'}}>User Join 🎈</h1>
          <p>Become a member of our world! 🌍✨</p>
        </div>

        <form onSubmit={handleRegister}>
          <div className="form-group-modern">
            <input
              className="form-input"
              placeholder="👤 Full Name"
              type="text"
              required
              onChange={(e) => setName(e.target.value)}
            />
          </div>

          <div className="form-group-modern">
             <input
              className="form-input"
              placeholder="✉️ Email Address"
              type="email"
              required
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>

          <div className="form-group-modern">
            <input
              className="form-input"
              placeholder="🔓 Create Password"
              type="password"
              required
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>

          <button 
            className="auth-submit-btn" 
            type="submit" 
            style={{ backgroundColor: '#fb3f7b', boxShadow: '0 4px 10px rgba(251, 63, 123, 0.3)' }}
          >
            Sign Up Now 🚀
          </button>
        </form>

        <div className="auth-footer-text">
          Already have an account? <Link to="/" className="auth-footer-link" style={{color: '#fb3f7b'}}>Sign In 🔐</Link>
          <div style={{marginTop: '1rem', fontSize: '0.75rem', fontWeight: 600, letterSpacing: '1px'}}>
            <Link to="/admin-secret" style={{color: '#94a3b8', textDecoration: 'none'}}>
               🛡️ SECURE ADMIN REGISTRATION
            </Link>
          </div>
        </div>
      </div>

       <div className="auth-copyright" style={{color: '#64748b'}}>
        © 2024 SecurePortal Pro • Multi-layered Protection 🛡️ ✨
      </div>
    </div>
  );
}

export default Register;
